import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import { TrendingUp, TrendingDown } from '@mui/icons-material';
import response from './response.json';

interface HeartRateData {
  currentHeartRate: number;
  restingHeartRate: number;
  heartRateTrend: number[];
}

export default function Widget() {
  const data = response.data as HeartRateData;
  const clipPathId = useId();
  const trendArrow = data.currentHeartRate > data.restingHeartRate ? <TrendingUp sx={{ fontSize: 16, color: '#10B981' }} /> : <TrendingDown sx={{ fontSize: 16, color: '#EF4444' }} />;
  const trendColor = data.currentHeartRate > data.restingHeartRate ? '#10B981' : '#EF4444';

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#1C1C1C' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ color: '#FFC107' }}>
              Current Heart Rate
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#FF5722' }}>
              {data.currentHeartRate} bpm
            </Typography>
            <Stack direction="row" alignItems="center" spacing={0.5} sx={{ mt: 0.5 }}>
              {trendArrow}
              <Typography variant="body2" sx={{ color: trendColor }}>
                {data.currentHeartRate - data.restingHeartRate} bpm from resting
              </Typography>
            </Stack>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: data.heartRateTrend,
                  color: '#FFC107',
                  curve: 'natural',
                  showMark: false,
                },
              ]}
              xAxis={[
                {
                  scaleType: 'linear',
                  data: data.heartRateTrend.map((_, i) => i),
                  id: 'time',
                  hide: true,
                },
              ]}
              yAxis={[{ id: 'heartRate' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="time"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsYAxis
                axisId="heartRate"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
